-- jamypg meta schema as text2sql target (PostgreSQL). Auto-generated by gen_testenv.py.

-- The same tables double as the live jamypg meta DB (server migrations are IF NOT EXISTS).

CREATE TABLE IF NOT EXISTS jamypg_users (
	id TEXT,
	username TEXT,
	display_name TEXT,
	email TEXT,
	password_hash TEXT,
	role TEXT,
	provider TEXT,
	provider_subject TEXT,
	is_active BOOLEAN,
	created_at TIMESTAMPTZ,
	updated_at TIMESTAMPTZ,
	last_login_at TIMESTAMPTZ,
	PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS jamypg_sessions (
	token_hash TEXT,
	user_id TEXT,
	created_at TIMESTAMPTZ,
	expires_at TIMESTAMPTZ,
	ip TEXT,
	user_agent TEXT,
	revoked_at TIMESTAMPTZ,
	PRIMARY KEY (token_hash)
);

CREATE TABLE IF NOT EXISTS jamypg_mcp_keys (
	id TEXT,
	user_id TEXT,
	name TEXT,
	key_hash TEXT,
	key_prefix TEXT,
	created_at TIMESTAMPTZ,
	expires_at TIMESTAMPTZ,
	last_used_at TIMESTAMPTZ,
	revoked_at TIMESTAMPTZ,
	rotated_from TEXT,
	PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS jamypg_db_profiles (
	id TEXT,
	owner_id TEXT,
	definition JSONB,
	visibility TEXT,
	created_at TIMESTAMPTZ,
	updated_at TIMESTAMPTZ,
	PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS jamypg_profile_grants (
	profile_id TEXT,
	user_id TEXT,
	permission TEXT,
	granted_by TEXT,
	granted_at TIMESTAMPTZ,
	PRIMARY KEY (profile_id, user_id)
);

CREATE TABLE IF NOT EXISTS jamypg_settings (
	key TEXT,
	value TEXT,
	updated_by TEXT,
	updated_at TIMESTAMPTZ,
	PRIMARY KEY (key)
);

CREATE TABLE IF NOT EXISTS jamypg_mcp_activity (
	id TEXT,
	created_at TIMESTAMPTZ,
	user_id TEXT,
	username TEXT,
	session_id TEXT,
	tool TEXT,
	kind TEXT,
	prompt TEXT,
	sql_text TEXT,
	profile TEXT,
	status TEXT,
	row_count INT,
	elapsed_ms BIGINT,
	params JSONB,
	PRIMARY KEY (id)
);



CREATE ROLE jamypg_ro LOGIN PASSWORD 'jamypg_ro_pw';
